const arquivo   = $input.first().json.arquivo;
const timestamp = $input.first().json.timestamp;
const erros     = $input.first().json.erros || [];

const lista = erros.map(e => `<li style='margin-bottom:6px'>${e}</li>`).join('');

const emailHtml = `
<div style='font-family:Arial,sans-serif;max-width:600px'>
  <h2 style='color:#c0392b'>&#9888; Erro em XML de PDV</h2>
  <table style='border-collapse:collapse;width:100%'>
    <tr><td style='padding:6px;font-weight:bold'>Arquivo</td><td>${arquivo}</td></tr>
    <tr><td style='padding:6px;font-weight:bold'>Data/Hora</td><td>${timestamp}</td></tr>
    <tr><td style='padding:6px;font-weight:bold'>Erros</td><td>${erros.length}</td></tr>
  </table>
  <h3>Detalhes:</h3>
  <ul>${lista}</ul>
</div>`;

const csvLinha = `${timestamp},${arquivo},${erros.length}`;

return [{ json: { emailHtml, csvLinha, arquivo, erros, timestamp } }];
